mapper.sql:
FROM knowledge_entry e
LEFT JOIN knowledge_file f
  ON e.id = f.entry_id
 AND f.is_current = 1
 AND f.status = 1
WHERE e.status = 1

    AND e.entry_type = #{request.entryType}


    AND f.original_file_name LIKE CONCAT('%', #{request.fileName}, '%')


    AND e.entry_code LIKE CONCAT('%', #{request.entryCode}, '%')


    AND e.title LIKE CONCAT('%', #{request.title}, '%')


    AND e.profession_code = #{request.professionCode}


    AND e.info_status = #{request.infoStatus}


    AND e.release_date  >=  #{request.startDate}


    AND e.release_date  <=  #{request.endDate}

mapper.select:
SELECT COUNT(1)
FROM knowledge_entry
WHERE entry_type = #{request.entryType}
  AND entry_code = #{request.entryCode}
  AND version = #{request.version}
  AND status = 1
  AND delete_marker = 0

    AND id != #{excludedEntryId}
